terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 6.0"
    }
  }
}

provider "aws" {
  region = "eu-west-2"
}

resource "aws_s3_bucket" "orders_invoices" {
  bucket = "dp-devpolaris-orders-prod-invoices"

  tags = {
    service     = "devpolaris-orders"
    environment = "prod"
    managed_by  = "terraform"
  }
}
